  ('social-worker-moex-07780', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體動力的概念，下列那一項是正確的？', '["團體動力是帶領團體的一種技巧和方法", "團體動力僅是指在任何時間內，被覺察到發生在團體裡的一些現象", "團體動力是社會科學研究的一個領域，是用來說明團體行為的一套基本知識", "團體動力強調團體思考（group think）比個人思考更為重要"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
