  ('social-worker-moex-07784', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對一個團體工作的進行成功與否，下列何者的專業評估是最不重要的？', '["成員的評估", "督導與同儕", "機構主管", "帶領者本身"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07785', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者說法是不妥的？', '["團體內的衝突具有潛在的破壞性和潛在的建設性", "團體內沒有衝突是會讓團體效能降低的", "團體內的衝突可帶來團體的凝聚、創新和成長", "所有的衝突都可以有效的被管理"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07786', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '問題解決取向的團體中何者對達成目標有利？', '["競爭的價值與態度", "負面的自我評價", "多元文化及個人的差異", "形塑互相合作的氛圍與規則"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07787', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '專業社工和科層體制之間的衝突中，何者是錯誤的？', '["社工重視創造與改變，而科層體制抗拒改變", "社工重視個人的成長與發展，而科層體制卻需要去個人化、去情緒化", "社工重視溝通，但是在科層體制中，溝通是無效的", "社工期待分享式領導，但是在科層體制中強調結構與地位"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07788', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '針對團體規範，下列那一項觀點是錯誤的？', '["成員在團體中職位排列的高低，會影響成員對規範遵守的程度。低地位的團體成員最不易認同團體規 範；高地位的成員有較大的自由違反團體規範", "團體領導者可以增加對團體中允許表達那些情緒、那些主題可討論那些是不可談的、解決問題或面對 任務時團體的模式、回饋團體的態度等固定行為模式的觀察，以確認出團體的規範", "團體成員不規律的出席、經常遲到、過度依賴領導者、少數成員支配團體互動等將會危害團體本身， 阻礙團體發展。以上陳述說明了團體規範的發展與團體價值觀有關聯", "團體對規範的選擇，如同團體對價值的選擇，都會嚴重地影響團體提供治療情境的能力。兩者均可對 團體治療目標產生功能性及非功能性的影響"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07789', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關單系統方法（single-system methods）和個案研究法（case study methods）的敘述，下列那一個答案是 正確的？', '["為發展和評估新的團體方案和方法，單系統方法和個案研究法特別適合用於發展性的評估", "單系統方法比個案研究法更受到團體工作者的歡迎", "相較於單系統方法，個案研究法需要對個案作較密集的分析", "為蒐集資料和評估團體，團體工作者可在例行工作之餘，運用單系統方法或個案研究法去發展和改進 團體實務"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
